  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import { getValidatedProp } from '@odf/shared/utils';
  4	import {
  5	  FileUpload,
  6	  FormGroup,
  7	  FormHelperText,
  8	  HelperText,
  9	  HelperTextItem,
 10	  ValidatedOptions,
 11	} from '@patternfly/react-core';
 12	import { KMSMaxFileUploadSize } from '../../../odf/constants';
 13	import { AzureConfig, ThalesConfig } from '../../../odf/types';
 14	
 15	export const FileUploadInput: React.FC<
 16	  FileUploadInputProps<AzureConfig | ThalesConfig>
 17	> = ({
 18	  id,
 19	  inputName,
 20	  helperText,
 21	  labelIcon,
 22	  className,
 23	  kmsState,
 24	  kmsStateClone,
 25	  updateKmsState,
 26	}) => {
 27	  const { t } = useCustomTranslation();
 28	  const KMSFileSizeErrorMsg = t(
 29	    'Invalid file: File size exceeds 4MB limit or incorrect file extension (only .pem files allowed).'
 30	  );
 31	
 32	  const FileReadErrorMsg = t('File read failed. Please try again.');
 33	
 34	  const setError = React.useCallback(
 35	    (errMsg: string) => {
 36	      kmsStateClone[id].value = '';
 37	      kmsStateClone[id].error = errMsg;
 38	      updateKmsState(kmsStateClone);
 39	    },
 40	    [kmsStateClone, updateKmsState, id]
 41	  );
 42	
 43	  const readFile = React.useCallback(
 44	    (file?: File, filename?: string) => {
 45	      const reader = new FileReader();
 46	      reader.onload = () => {
 47	        const input = reader.result;
 48	        kmsStateClone[id].value = input.toString();
 49	        kmsStateClone[id].error = '';
 50	        kmsStateClone[id].fileName = filename;
 51	        updateKmsState(kmsStateClone);
 52	      };
 53	      reader.onerror = () => {
 54	        kmsStateClone[id].fileName = filename;
 55	        setError(FileReadErrorMsg);
 56	      };
 57	      if (file) {
 58	        reader.readAsText(file, 'UTF-8');
 59	      } else {
 60	        kmsStateClone[id].value = '';
 61	        kmsStateClone[id].error = '';
 62	        kmsStateClone[id].fileName = '';
 63	        updateKmsState(kmsStateClone);
 64	      }
 65	    },
 66	    [setError, kmsStateClone, updateKmsState, FileReadErrorMsg, id]
 67	  );
 68	
 69	  const handleClear = (
 70	    _event: React.MouseEvent<HTMLButtonElement, MouseEvent>
 71	  ) => {
 72	    readFile();
 73	  };
 74	
 75	  const updateCertificate = React.useCallback(
 76	    (value: File, filename: string) => {
 77	      readFile(value, filename);
 78	    },
 79	    [readFile]
 80	  );
 81	
 82	  return (
 83	    <FormGroup
 84	      key={`kms-${id}`}
 85	      fieldId={id}
 86	      label={inputName}
 87	      labelHelp={labelHelp}
 88	      className={`${className}__form-body`}
 89	      isRequired
 90	    >
 91	      <FileUpload
 92	        id={id}
 93	        value={kmsState[id].value}
 94	        filename={kmsState[id].fileName}
 95	        onClearClick={handleClear}
 96	        onFileInputChange={(_event, file) => updateCertificate(file, file.name)}
 97	        hideDefaultPreview
 98	        filenamePlaceholder={t('Upload a .PEM file here...')}
 99	        dropzoneProps={{
100	          accept: {
101	            'text/plain': ['.pem'],
102	          },
103	          maxSize: KMSMaxFileUploadSize,
104	          onDropRejected: () => setError(KMSFileSizeErrorMsg),
105	        }}
106	        data-testid={id}
107	      />
108	      <FormHelperText>
109	        <HelperText>
110	          <HelperTextItem variant={getValidatedProp(kmsState[id].error)}>
111	            {getValidatedProp(!kmsState[id].error) === ValidatedOptions.default
112	              ? kmsState[id].error
113	              : helperText}
114	          </HelperTextItem>
115	        </HelperText>
116	      </FormHelperText>
117	    </FormGroup>
118	  );
119	};
120	
121	export type UploadInputItem = {
122	  id: string;
123	  inputName: string;
124	};
125	
126	type FileUploadInputProps<T extends AzureConfig | ThalesConfig> =
127	  UploadInputItem & {
128	    helperText?: string;
129	    labelIcon?: React.ReactElement;
130	    className: string;
131	    kmsState: T;
132	    kmsStateClone: T;
133	    updateKmsState: (kmsConfig: T) => void;
134	  };

